    private static final int READ_TIMEOUT_MS = 10000;
    private static final int MAX_REDIRECTS = 5;

    public boolean processImageFromUrl(String imageUrl) {
        if (imageUrl == null || imageUrl.trim().isEmpty()) {
            System.err.println("Image URL must not be null or empty.");
            return false;
        }

        try {
            URL url = validateAndCreateUrl(imageUrl.trim());
            BufferedImage image = downloadImage(url);

            if (image == null) {
                System.err.println("The URL does not contain a supported image format.");
                return false;
            }

            System.out.println("Image processed successfully: " + image.getWidth() + "x" + image.getHeight());
            return true;
        } catch (IllegalArgumentException | IOException e) {
            System.err.println("Error processing image from URL: " + e.getMessage());
            return false;
        }
    }

    private URL validateAndCreateUrl(String imageUrl) throws IOException {
        try {
            URI uri = URI.create(imageUrl);
            String scheme = uri.getScheme();

            if (scheme == null || (!"http".equalsIgnoreCase(scheme) && !"https".equalsIgnoreCase(scheme))) {
                throw new IllegalArgumentException("Only HTTP and HTTPS URLs are supported.");
            }

            return uri.toURL();
        } catch (IllegalArgumentException e) {
            throw new IllegalArgumentException("Invalid image URL: " + imageUrl, e);
        }
    }

    private BufferedImage downloadImage(URL url) throws IOException {
        URL currentUrl = url;
        int redirectCount = 0;

        while (redirectCount <= MAX_REDIRECTS) {
            HttpURLConnection connection = (HttpURLConnection) currentUrl.openConnection();
            connection.setConnectTimeout(CONNECT_TIMEOUT_MS);
            connection.setReadTimeout(READ_TIMEOUT_MS);
            connection.setInstanceFollowRedirects(false);
            connection.setRequestMethod("GET");
            connection.setRequestProperty("Accept", "image/*");

            int responseCode = connection.getResponseCode();

            if (isRedirect(responseCode)) {
                String location = connection.getHeaderField("Location");
                connection.disconnect();

                if (location == null || location.isBlank()) {
                    throw new IOException("Redirect response missing Location header.");
                }

                currentUrl = resolveRedirectUrl(currentUrl, location);
                redirectCount++;
                continue;
            }

            if (responseCode != HttpURLConnection.HTTP_OK) {
                connection.disconnect();
                throw new IOException("Failed to download image. HTTP status: " + responseCode);
            }

            String contentType = connection.getContentType();
            if (contentType != null && !contentType.toLowerCase(Locale.ROOT).startsWith("image/")) {
                connection.disconnect();
                throw new IOException("URL does not point to an image. Content-Type: " + contentType);
            }

            try (InputStream inputStream = connection.getInputStream()) {
                BufferedImage image = ImageIO.read(inputStream);
                if (image == null) {
                    throw new IOException("Unable to decode image or unsupported image format.");
                }
                return image;
            } finally {
                connection.disconnect();
            }
        }

        throw new IOException("Too many redirects.");
    }

    private boolean isRedirect(int responseCode) {
        return responseCode == HttpURLConnection.HTTP_MOVED_PERM
                || responseCode == HttpURLConnection.HTTP_MOVED_TEMP
                || responseCode == HttpURLConnection.HTTP_SEE_OTHER
                || responseCode == 307
                || responseCode == 308;
    }

    private URL resolveRedirectUrl(URL baseUrl, String location) throws MalformedURLException {
        return new URL(baseUrl, location);
    }
