    private void validateUri(URI uri) throws IOException, URISyntaxException {
        if (uri.getScheme() == null) {
            throw new IOException("URL scheme is required");
        }

        String scheme = uri.getScheme().toLowerCase(Locale.ROOT);
        if (!"http".equals(scheme) && !"https".equals(scheme)) {
            throw new IOException("Only HTTP and HTTPS URLs are allowed");
        }

        String host = uri.getHost();
        if (host == null || host.isBlank()) {
            throw new IOException("URL host is required");
        }

        String asciiHost = IDN.toASCII(host);
        InetAddress[] addresses = InetAddress.getAllByName(asciiHost);
        for (InetAddress address : addresses) {
